package base;import org.junit.jupiter.api.AfterEach;import org.junit.jupiter.api.BeforeEach;import org.openqa.selenium.WebDriver;import org.openqa.selenium.chrome.ChromeDriver;import org.openqa.selenium.chrome.ChromeOptions;public class BaseTest {    protected WebDriver driver;    @BeforeEach    void setUp() {        ChromeOptions options = new ChromeOptions();        if (System.getenv("GITHUB_ACTIONS") != null) {            options.addArguments("--headless=new");            options.addArguments("--no-sandbox");            options.addArguments("--disable-dev-shm-usage");        }        driver = new ChromeDriver(options);        driver.manage().window().maximize();    }    @AfterEach    void tearDown() {        if (driver != null) {            driver.quit();        }    }}